parameters.query:
query GetOrgPipeTags($organizationUuid: ID!, $search: String) {
  tagsByCategory(organizationUuid: $organizationUuid, search: $search) {
    uuid
    name            # nome da categoria (ex.: "Departments" ou "Uncategorized")
    total           # total de tags nesta categoria
    tags {
      uuid
      name
      description
      taggedPipes {
        pipes {
          edges {
            node {
              id
              name
              uuid
            }
          }
        }
      }
    }
  }
}

query GetCardFields($cardId: ID!) {
  card(id: $cardId) {
    id
    title
    fields {
      field {
        id
        label
        type
      }
      value          # human-readable value
      report_value   # normalized value (useful for numbers/selects)
      array_value
    }
  }
}

