      push(v.id);
    } else if (typeof v === 'string') {
      v.split(',').forEach(push);
    }
    return Array.from(new Set(out));
  };

  const curr = norm($json.rede);          // ex: [], ["abc"], [{id: "abc"}]
  const prev = norm($json.prevRedeId);    // ex: []

  // If prev is empty and curr has values, record the additions in history
  if (!prev.length && curr.length) {
    return curr.map(id => `Definiu a rede: ${id}`);
  }

  // Otherwise, compute diffs normally
  const sPrev = new Set(prev), sCurr = new Set(curr);
  const added = curr.filter(id => !sPrev.has(id));
  const removed = prev.filter(id => !sCurr.has(id));

  if (added.length === 1 && removed.length === 1) {
    return [`Alterou a rede: ${removed[0]} → ${added[0]}`];
  }

  const msgs = [];
  added.forEach(id => msgs.push(`${id}`));
  removed.forEach(id => msgs.push(`${id}`));
  return msgs;
})() }}

