parameters.jsCode:
// Node: "Init Report"
const staticData = $getWorkflowStaticData('global');
staticData.results = []; // Create an empty list

return items;

// 1. Initialize variables
let originalItem = {};
let numeroVenda = null;

// 2. Try to get the original data (Invoice Data)
try {
  // Try to get from the Loop node first (most reliable source of original data)
  originalItem = $('Loop faturas').item.json;
} catch (e) {
  // Fallback to current input if Loop is not accessible
  originalItem = $input.first().json;
}

// 3. Try to get the Sale Number from the "Definir variáveis" node
// If the workflow went down the "False" path (Validation Failed), this node never ran,
// so this block will fail/throw, leaving numeroVenda as null.
try {
  const vars = $('Definir variáveis').item.json;
  if (vars && vars.numeroVenda) {
    numeroVenda = vars.numeroVenda;
  }
} catch (e) {
  // Node didn't execute for this item -> Logic Failure
  numeroVenda = null; 
}

// 4. Determine Status based on Data (Not just Errors)
// A success MUST have a Sale Number. If it's null, something went wrong.
const currentItem = $input.first();
const technicalError = currentItem.error || (currentItem.json && currentItem.json.error);

let status = 'Sucesso';
let message = 'Processado com sucesso.';

if (technicalError) {
  status = 'Erro';
  const rawError = technicalError.message || JSON.stringify(technicalError);
  message = `Erro Técnico: ${rawError}`;
} else if (!numeroVenda) {
  // No technical error, but no Sale Number either -> Logic Failure (Validation)
  status = 'Erro';
  message = 'Falha de Validação: Cliente não encontrado, duplicado ou erro de fluxo.';
}

// 5. Return the formatted log
return [{
  json: {
    data: new Date().toISOString(),
    linha: originalItem.Linha || 0,
    cliente: originalItem.Nome || 'N/A',
    numeroVenda: numeroVenda || 'N/A',
    status: status,
    mensagem: message
  }
}];

