parameters.functionCode:
// Monta uma lista de contatos (um item por papel) a partir dos campos já coletados
// e inclui IDs necessários para as próximas mutações.
const d = $json;
const fichaCardId = $items('Pegar informação da ficha')[0].json.data.card.id;
const clienteRaw = (d.cliente || '').toString();
const clienteCardId = clienteRaw.split(',')[0].trim(); // assume um cliente por ficha

// Ajuste os fieldIds abaixo se necessário para os campos de RELACIONAMENTO na ficha
const fichaFieldIds = {
  signatario: 'signat_rio',
  financeiro: 'contato_financeiro',
  testemunha: 'testemunha',
  implantacao: 'contato_de_implanta_o',
};

const contacts = [
  { role: 'signatario',  name: d.nomeSignatario,  email: d.emailSignatario,  phone: null,                   fichaFieldId: fichaFieldIds.signatario },
  { role: 'financeiro',  name: d.nomeFinanceiro,  email: d.emailFinanceiro,  phone: null,                   fichaFieldId: fichaFieldIds.financeiro },
  { role: 'testemunha',  name: d.nomeTestemunha,  email: d.emailTestemunha,  phone: null,                   fichaFieldId: fichaFieldIds.testemunha },
  { role: 'implantacao', name: d.nomeImplementacao, email: d.emailImplementacao, phone: d.celularImplementacao, fichaFieldId: fichaFieldIds.implantacao },
];

return contacts
  .filter(c => c.email && String(c.email).trim().length > 0)
  .map(c => ({
    json: {
      ...c,
      clienteCardId,
      fichaCardId,
    }
  }));

