      rule_batches_per_type: manifest.expected_counts ? manifest.expected_counts.rule_batches_per_type : null,
    },
    created: {
      item_cards_total: createdItemIds.length,
      rule_cards_total: createdRuleIds.length,
      processed_rule_cards_total: processedRuleIds.length,
      item_batches_success: itemResults.filter((entry) => entry.status === 'success').length,
      item_batches_failed: failedItemBatches.length,
      rule_batches_processed: ruleResults.filter((entry) => entry.status === 'processed').length,
      rule_batches_failed: failedRuleBatches.length,
    },
    failures: {
      item_batches: failedItemBatches,
      rule_batches: failedRuleBatches,
      skipped_rule_batches: Array.isArray(run.skippedRuleBatches) ? run.skippedRuleBatches : [],
    },
    partial_cleanup: {
      created_item_ids: Array.isArray(run.partialCreatedItemIds) ? run.partialCreatedItemIds : [],
      created_rule_ids: Array.isArray(run.partialCreatedRuleIds) ? run.partialCreatedRuleIds : [],
    },
    validation: validationSummary,
  },
}];

