  const sd = $getWorkflowStaticData('global');
  if (!Array.isArray(sd.logs)) sd.logs = [];
  sd.logs.push({
    id_do_teste: String(id_do_teste),
    resultado: ok ? 'OK' : 'ERRO',
    observacoes: String(observacoes || '')
  });
}


