const card = validation?.data?.card;
const regras = extractRegrasIds(card);
if (!containsId(regras, createdId)) ok = false;

const obs = [
  `createCard.id=${asString(createdId)}`,
  `Esperado: 1259910277 conter ${createdId} em regras_de_faturamento`,
  `1259910277 -> ${JSON.stringify(regras)}`
].join(' | ');

pushLog('1', ok, obs);
return $input.all();

