={{ (() => {
  const fields = $('Pegar informação do contato').item.json.data?.card?.fields ?? [];
  const get = (id) => fields.find(x => (x.field?.id ?? x.indexName ?? '') === id);
  const clean = s => String(s ?? '').trim();
  const f = get('ultima_rede');
  const empty = [];

  if (!f) return empty;

  // If it's already an array, take the first non-empty entry
  if (Array.isArray(f.array_value) && f.array_value.length) {
    const v = f.array_value[0];
    if (v && typeof v === 'object' && v.id != null) return [String(v.id)];
    if (typeof v === 'string' && clean(v)) return [clean(v)];
  }

  // Single value cases
  if (typeof f.value === 'string' && clean(f.value)) return [clean(f.value)];
  if (f.value && typeof f.value === 'object' && f.value.id != null) return [String(f.value.id)];

  // If nothing valid, return an empty array (not an empty string)
  return empty;
})() }}

